import json
import boto3

sns_client = boto3.client('sns')

def lambda_handler(event, context):
    message_content = event.get('messageContent')
    topic_arn = event.get('topicArn')
    notification_type = event.get('notificationType', 'default') # 'default', 'sms', 'email'
    subject = event.get('subject', 'Default Notification Subject') # For email type

    if not message_content or not topic_arn:
        raise ValueError("Both 'messageContent' and 'topicArn' are required in the event data.")

    try:
        publish_params = {
            'TopicArn': topic_arn,
            'Message': message_content,
        }

        if notification_type == 'email':
            publish_params['Subject'] = subject
            # For email, MessageStructure can be 'json' to send different messages for different protocols
            # Here we're sending the same message content for simplicity, but could differentiate
            # publish_params['MessageStructure'] = 'json'
            # publish_params['Message'] = json.dumps({
            #     'default': message_content,
            #     'email': message_content,
            #     'sqs': message_content,
            #     'sms': message_content
            # })
        elif notification_type == 'sms':
            # For SMS, the message content is often the direct message to send.
            # SNS automatically handles SMS publishing if a phone number is subscribed or direct publish is used.
            # If publishing to a topic that has SMS subscribers, this is sufficient.
            # If directly publishing to a phone number (not requested by prompt, but for completeness):
            # publish_params['MessageAttributes'] = {
            #     'AWS.SNS.SMS.SMSType': {
            #         'DataType': 'String',
            #         'StringValue': 'Transactional' # or 'Promotional'
            #     }
            # }
            pass # No specific extra params for SMS via topic publish compared to 'default'
        elif notification_type == 'default':
            pass # No specific extra params for default
        else:
            raise ValueError(f"Unsupported notificationType: {notification_type}. Supported types are 'default', 'sms', 'email'.")

        response = sns_client.publish(**publish_params)

        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'SNS message published successfully!',
                'messageId': response['MessageId'],
                'topicArn': topic_arn,
                'notificationType': notification_type
            })
        }
    except Exception as e:
        print(f"Error publishing message to SNS: {e}")
        raise # Re-raise the exception to indicate a failure